def range_summary(nums):
    if not nums:
        return ''

    prev_num = min(nums)
    max_run = [prev_num]
    curr_run = 1

    for num in sorted(set(nums)):
        if num == prev_num + 1:
            curr_run += 1
        else:
            if curr_run > 1:
                max_run.append(f'{max(max_run)}-{min(max_run)}')
            max_run = [num]
            curr_run = 1
        prev_num = num

    if curr_run > 1:
        max_run.append(f'{max(max_run)}-{min(max_run)}')

    return ','.join(max_run)
